import React from 'react'


interface Props {
    title:string;
    subtitle:string;
    icon?: React.ReactNode;
}

const Tile = ({ title, subtitle, icon }: Props) => {
  return (
    <div className="w-full lg:w-6/12 xl:w-3/12 px-4 mb-6">
      <div className="relative flex flex-col min-w-0 break-words bg-white rounded-lg shadow-lg hover:shadow-xl transition-shadow duration-300">
        <div className="flex-auto p-4">
          <div className="flex items-center">
            {icon && <div className="text-blue-500 text-3xl mr-4">{icon}</div>}
            <div className="flex flex-col">
              <h5 className="text-blueGray-400 uppercase font-bold text-xs mb-1">
                {title}
              </h5>
              <span className="font-bold text-xl leading-snug">{subtitle}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Tile;
